export const conversationsApi = {
	/**
	 * `GET /conversations` — Leveret conversations list (warren-af15 /
	 * 763f). Optional `?project` / `?plot` (mutually exclusive) and
	 * `?status` narrow the set; the bare call lists every conversation,
